CREATE OR REPLACE VIEW vr_nsk_015_010000 (monthly_date, deposit_account_no, item_type, membership_no, deposit_type_code, deposit_name, memname, accumulate_interest, last_calcint_date, deposit_balance, int_arrear, arrear_date) AS SELECT sc_cls_mon_dep_accno.monthly_date,
         sc_cls_mon_dep_accno.deposit_account_no,
         '' as item_type,   
         sc_cls_mon_dep_accno.membership_no,   
         sc_cls_mon_dep_accno.deposit_type_code,   
         sc_dep_m_rule.deposit_name,
         pka_com_function.fp_get_member_name( sc_cls_mon_dep_accno.membership_no ) as memname,   
         sc_cls_mon_dep_accno.accumulate_interest ,   
         sc_cls_mon_dep_accno.last_calcint_date,   
         sc_cls_mon_dep_accno.deposit_balance,   
         sc_cls_mon_dep_accno.int_arrear,   
         ( sc_cls_mon_dep_accno.monthly_date + ( CASE WHEN   sc_dep_m_constant.clsmonth_include_lastday ='1' THEN  1   ELSE 0 END ) * interval '1 day'  ) as arrear_date
    FROM sc_cls_mon_dep_accno,
         sc_dep_m_rule ,
         sc_dep_m_constant  
   WHERE 1=1
   and sc_cls_mon_dep_accno.deposit_type_code = sc_dep_m_rule.deposit_type_code
   and sc_dep_m_rule.invest_status = '0'
--and sc_cls_mon_dep_accno.monthly_date = '30/11/2024'  
ORDER BY sc_cls_mon_dep_accno.deposit_account_no;

